SELECT HOMEPAGE_ID, GROUP_IDX, CATEGORY_IDX, TRAINING_IDX, STUDENT_IDX, MEMBER_ID, MEMBER_KEY, APPLICANT_NAME, APPLICANT_BIRTH , APPLICANT_OLD, APPLICANT_SEX, APPLICANT_ZIPCODE, APPLICANT_ADDRESS, APPLICANT_ADDRESS_DETAIL, APPLICANT_PHONE, APPLICANT_CELL_PHONE, SELF_YN , STUDENT_NAME, STUDENT_BIRTH, STUDENT_SEX, STUDENT_ZIPCODE, STUDENT_ADDRESS, STUDENT_ADDRESS_DETAIL, STUDENT_SCHOOL, STUDENT_HACK, STUDENT_OLD, PAY1_YN, PAY2_YN, PAY3_YN , SELF_INFO_YN, APPLY_TYPE, APPLY_STATUS, TO_CHAR(ADD_DATE, 'yyyy-mm-dd hh24:mi') AS ADD_DATE, CANCEL_ID, CANCEL_DATE, FAMILY_RELATION, FAMILY_NAME, FAMILY_CELL_PHONE, FAMILY_CONFIRM_YN, FAMILY_DESC, student_ban, student_remark, student_family_count, getCodeIdToCodeName('CMS', 'C0020', STUDENT_HACK) AS student_hack_str, web_id, student_location_code, getCodeIdToCodeName('CMS', 'C0022', student_location_code) AS student_location_code_str, student_neis_cd, student_training_num, student_organization, student_rank, student_course_taken_yn, belong_name FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id} AND GROUP_IDX = #{group_idx} AND CATEGORY_IDX = #{category_idx} AND TRAINING_IDX = #{training_idx}
AND APPLY_STATUS = #{apply_status}
ORDER BY APPLY_STATUS, STUDENT_IDX ASC

${pagingTop} SELECT A.*, CASE WHEN A.CNT = 0 THEN '2' WHEN (A.ATTEND_CNT/A.CNT)*100 >= #{cert_percent} THEN '1' ELSE '2' END AS STUDENT_STATUS, (SELECT COUNT(*) FROM BLACKLIST WHERE HOMEPAGE_ID = A.HOMEPAGE_ID AND MEMBER_KEY = A.MEMBER_KEY AND INSTR(BLACK_TYPE, '10') != 0) as isBlackList FROM ( SELECT HOMEPAGE_ID, GROUP_IDX, CATEGORY_IDX, TRAINING_IDX, STUDENT_IDX, MEMBER_ID, MEMBER_KEY, APPLICANT_NAME, APPLICANT_BIRTH , APPLICANT_OLD, APPLICANT_SEX, APPLICANT_ZIPCODE, APPLICANT_ADDRESS, APPLICANT_ADDRESS_DETAIL, APPLICANT_PHONE, APPLICANT_CELL_PHONE, SELF_YN , STUDENT_NAME, STUDENT_BIRTH, STUDENT_SEX, STUDENT_ZIPCODE, STUDENT_ADDRESS, STUDENT_ADDRESS_DETAIL, STUDENT_SCHOOL, STUDENT_HACK, STUDENT_OLD , SELF_INFO_YN, APPLY_TYPE, APPLY_STATUS, TO_CHAR(a.ADD_DATE, 'yyyy-mm-dd hh24:mi') AS ADD_DATE, CANCEL_ID, CANCEL_DATE, WEB_ID , (SELECT TRAINING_COUNT FROM TRAINING WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX) AS CNT , (SELECT NVL(SUM(DECODE(status, '1', 1, '2', 1, 0)) - TRUNC(SUM(DECODE(status, '2', 1, 0))/3), 0) FROM TRAINING_BOOK WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND STUDENT_IDX = a.STUDENT_IDX) as ATTEND_CNT , student_ban, student_remark, student_family_count, student_location_code, getCodeIdToCodeName('CMS', 'C0022', student_location_code) AS student_location_code_str, student_neis_cd, student_training_num, student_organization, student_rank, student_course_taken_yn, belong_name FROM TRAINING_STUDENT a WHERE a.DELETE_YN = 'N' AND a.HOMEPAGE_ID = #{homepage_id} AND a.GROUP_IDX = #{group_idx} AND a.CATEGORY_IDX = #{category_idx} AND a.TRAINING_IDX = #{training_idx}
AND ${search_type} LIKE '%'||#{search_text}||'%'
) A ORDER BY A.APPLY_STATUS, A.STUDENT_IDX ASC ${pagingBottom}

SELECT COUNT(*) FROM ( SELECT HOMEPAGE_ID, GROUP_IDX, CATEGORY_IDX, TRAINING_IDX, STUDENT_IDX, MEMBER_ID, MEMBER_KEY, APPLICANT_NAME, APPLICANT_BIRTH , APPLICANT_OLD, APPLICANT_SEX, APPLICANT_ZIPCODE, APPLICANT_ADDRESS, APPLICANT_ADDRESS_DETAIL, APPLICANT_PHONE, APPLICANT_CELL_PHONE, SELF_YN , STUDENT_NAME, STUDENT_BIRTH, STUDENT_SEX, STUDENT_ZIPCODE, STUDENT_ADDRESS, STUDENT_ADDRESS_DETAIL, STUDENT_SCHOOL, STUDENT_HACK, STUDENT_OLD , SELF_INFO_YN, APPLY_TYPE, APPLY_STATUS, TO_CHAR(a.ADD_DATE, 'yyyy-mm-dd hh24:mi') AS ADD_DATE, CANCEL_ID, CANCEL_DATE , (SELECT TRAINING_COUNT FROM TRAINING WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX) AS CNT , (SELECT NVL(SUM(DECODE(status, '1', 1, '2', 1, 0)) - TRUNC(SUM(DECODE(status, '2', 1, 0))/3), 0) FROM TRAINING_BOOK WHERE HOMEPAGE_ID = a.HOMEPAGE_ID AND GROUP_IDX = a.GROUP_IDX AND CATEGORY_IDX = a.CATEGORY_IDX AND TRAINING_IDX = a.TRAINING_IDX AND STUDENT_IDX = a.STUDENT_IDX) as ATTEND_CNT , student_ban, student_remark, student_family_count FROM TRAINING_STUDENT a WHERE a.DELETE_YN = 'N' AND a.HOMEPAGE_ID = #{homepage_id} AND a.GROUP_IDX = #{group_idx} AND a.CATEGORY_IDX = #{category_idx} AND a.TRAINING_IDX = #{training_idx}
AND ${search_type} LIKE '%'||#{search_text}||'%'
) A

SELECT HOMEPAGE_ID, GROUP_IDX, CATEGORY_IDX, TRAINING_IDX, STUDENT_IDX, MEMBER_ID, MEMBER_KEY, APPLICANT_NAME, APPLICANT_BIRTH, web_id , APPLICANT_OLD, APPLICANT_SEX, APPLICANT_ZIPCODE, APPLICANT_ADDRESS, APPLICANT_ADDRESS_DETAIL, APPLICANT_PHONE, APPLICANT_CELL_PHONE, SELF_YN , STUDENT_NAME, STUDENT_BIRTH, STUDENT_SEX, STUDENT_ZIPCODE, STUDENT_ADDRESS, STUDENT_ADDRESS_DETAIL, STUDENT_SCHOOL, STUDENT_HACK, STUDENT_OLD , SELF_INFO_YN, APPLY_TYPE, APPLY_STATUS, TO_CHAR(ADD_DATE, 'yyyy-mm-dd hh24:mi') AS ADD_DATE, cancel_id, cancel_date , FAMILY_RELATION, FAMILY_NAME, FAMILY_CELL_PHONE, FAMILY_CONFIRM_YN, FAMILY_DESC , student_ban, student_remark, student_family_count, student_location_code, getCodeIdToCodeName('CMS', 'C0022', student_location_code) AS student_location_code_str, student_neis_cd, student_training_num, student_organization, student_rank, student_course_taken_yn, belong_name FROM TRAINING_STUDENT WHERE DELETE_YN = 'N' AND HOMEPAGE_ID = #{homepage_id} AND GROUP_IDX = #{group_idx} AND CATEGORY_IDX = #{category_idx} AND TRAINING_IDX = #{training_idx}
AND STUDENT_IDX = #{student_idx}
AND MEMBER_KEY = #{member_key} AND APPLY_STATUS != '99'

