UPDATE
	TRAINING_STUDENT
SET
	APPLY_STATUS 	= '99',
	CANCEL_DATE 	= SYSDATE,
	CANCEL_ID 		= #{cancel_id}
WHERE
	DELETE_YN 			= 'N'
	AND HOMEPAGE_ID 	= #{homepage_id}
	AND GROUP_IDX 		= #{group_idx}
	AND CATEGORY_IDX 	= #{category_idx}
	AND TRAINING_IDX 		= #{training_idx}
	AND STUDENT_IDX 	= #{student_idx}

