SET DELETE_YN 					= 'Y'
	,APPLY_STATUS				= '99'

	, MOD_ID					= #{mod_id}
	, MOD_DATE					= SYSDATE
WHERE
	HOMEPAGE_ID = #{homepage_id} AND GROUP_IDX = #{group_idx} AND CATEGORY_IDX = #{category_idx} AND TRAINING_IDX = #{training_idx}

	AND STUDENT_IDX = #{student_idx}

