SELECT
	REPLACE(a.END_DATE, '-', '')||'-'||LPAD(REPLACE(a.HOMEPAGE_ID, 'h', ''), 2, '0')||a.CATEGORY_IDX||LPAD(TRAINING_IDX, 2, '0')||'-'||LPAD(b.NUM, 3, '0') AS NUM,
	a.END_DATE, a.TRAINING_NAME, a.TRAINING_STAGE, a.START_DATE||' ~ '||a.END_DATE AS TRAINING_DATE, (to_date(a.end_time, 'HH24:MI') - to_date(a.start_time, 'HH24:MI'))*24 as training_status,
	b.STUDENT_NAME, c.HOMEPAGE_NAME, b.student_organization, replace(b.student_birth, '-', '.') student_birth, 
	a.CERTIFICATE_TEXT, a.TRAINING_COURSE, a.TRAINING_PERIOD,
	 (
      SELECT
			code_name
		FROM
			TRAINING_CODE2
		WHERE
			training_code = a.large_category_idx
      ) as family_name
FROM
	TRAINING a, CMS_HOMEPAGE c, ( SELECT rownum num, Z.*
				FROM (
					SELECT
						STUDENT_IDX, STUDENT_NAME, APPLY_STATUS, student_organization, student_birth
					FROM
						TRAINING_STUDENT
					WHERE
						DELETE_YN 		= 'N'
						AND HOMEPAGE_ID 	= #{homepage_id}
						AND GROUP_IDX 		= #{group_idx}
						AND CATEGORY_IDX 	= #{category_idx}
						AND TRAINING_IDX 		= #{training_idx}
					ORDER BY STUDENT_NAME
				) Z ) b
WHERE
	a.HOMEPAGE_ID 		= c.homepage_id
	AND a.HOMEPAGE_ID 	= #{homepage_id}
	AND a.GROUP_IDX 	= #{group_idx}
	AND a.CATEGORY_IDX 	= #{category_idx}
	AND a.TRAINING_IDX 	= #{training_idx}
	AND b.STUDENT_IDX 	= #{student_idx}

