SELECT result.*, CASE WHEN result.TRAINING_COUNT = 0 THEN '2' WHEN result.ATTEND_CNT < 70 THEN '2' WHEN result.ATTEND_CNT >= 70 THEN '1' END AS STUDENT_STATUS FROM (SELECT a.TRAINING_COUNT, b.homepage_id, b.group_idx, b.category_idx, b.training_idx, b.student_idx, b.member_id, b.member_key, b.applicant_name, b.applicant_birth, b.applicant_old, b.applicant_sex, b.applicant_zipcode, b.applicant_address, b.applicant_address_detail, b.applicant_phone, b.applicant_cell_phone, b.self_yn, b.student_name, b.student_birth, b.student_old, b.student_sex, b.student_zipcode, b.student_address, b.student_address_detail, b.student_school, b.student_hack, b.self_info_yn, b.apply_type, b.apply_status, b.pay1_yn, b.pay2_yn, b.pay3_yn, b.cancel_date, b.cancel_id, b.add_date, b.add_id, b.mod_date, b.mod_id, b.delete_yn, b.family_relation, b.family_name, b.family_confirm_yn, b.family_desc, b.web_id, b.student_family_count, b.student_ban, b.student_remark, b.sub_category_idx, b.student_location_code, b.student_neis_cd, b.student_training_num, b.large_category_idx, b.group_temp, b.category_temp, b.training_temp, CASE WHEN a.training_count = 0 THEN 0 ELSE ((SELECT NVL(SUM(DECODE(status, '1', 1, '2', 1, 0)) - TRUNC(SUM(DECODE(status, '2', 1, 0))/3), 0) FROM TRAINING_BOOK WHERE HOMEPAGE_ID = b.HOMEPAGE_ID AND GROUP_IDX = b.GROUP_IDX AND CATEGORY_IDX = b.CATEGORY_IDX AND TRAINING_IDX = b.TRAINING_IDX AND STUDENT_IDX = b.STUDENT_IDX)/a.training_count)*100 END as ATTEND_CNT FROM (SELECT homepage_id, group_idx, category_idx, training_idx, training_name, training_desc, training_etc, training_stage, training_target, training_status, training_join_unit, training_limit_count, training_backup_count, training_offline_count, teacher_idx, training_join_limit_unit, training_join_limit_value, start_join_date, start_join_time, end_join_date, end_join_time, training_day, start_date, start_time, end_date, end_time, training_count, plan_file_name, real_file_name, file_extension, file_size, member_yn, use_yn, print_seq, certificate_yn, certificate_rate, survey_idx, add_date, add_id, mod_date, mod_id, delete_yn, training_same_limit_count, image_plan_file_name, image_real_file_name, image_file_extension, image_file_size, family_yn, limit_hak, calendar_view_yn, limit_hak_yn, family_count_yn, agent_yn, school_info_yn, remark_yn, limit_hak2, program_classification1, program_classification2, program_classification3, program_subject, program_age_div, sub_category_idx, neis_location_yn, neis_cd_yn, neis_training_num_yn, large_category_idx, group_temp, category_temp, training_temp FROM TRAINING WHERE HOMEPAGE_ID = #{homepage_id} AND DELETE_YN = 'N' AND START_DATE > #{search_start_date} OR END_DATE < #{search_end_date} ) a, TRAINING_STUDENT b WHERE b.HOMEPAGE_ID = a.HOMEPAGE_ID AND b.GROUP_IDX = a.GROUP_IDX AND b.CATEGORY_IDX = a.CATEGORY_IDX AND b.TRAINING_IDX = a.TRAINING_IDX AND b.DELETE_YN = 'N' AND b.APPLY_STATUS = '1'
AND b.
) result

